import numpy as np
from collections import defaultdict
import math

STOPWORDS = {'a','an','the','is','are','was','were','in','on','at','to','of','and','or','for','with','it','this','that'}

class TextPreprocessor:
    def __init__(self, stopwords=STOPWORDS):
        self.stopwords = stopwords

    def process(self, text):
        tokens = text.lower().split()
        return [t for t in tokens if t not in self.stopwords and len(t) > 0]


class InvertedIndex:
    def __init__(self):
        # term -> {doc_id: tf}
        self.index = defaultdict(dict)
        self.doc_lengths = {}  # doc_id -> number of tokens
        self.n_docs = 0

    def add_document(self, doc_id, tokens):
        self.n_docs += 1
        self.doc_lengths[doc_id] = len(tokens)
        tf_counter = defaultdict(int)
        for t in tokens:
            tf_counter[t] += 1
        for term, count in tf_counter.items():
            self.index[term][doc_id] = count

    def get_postings(self, term):
        return self.index.get(term, {})

    def df(self, term):
        return len(self.index.get(term, {}))


class TFIDFScorer:
    def __init__(self, index, n_docs):
        self.index = index
        self.n_docs = n_docs

    def _idf(self, term):
        df = self.index.df(term)
        if df == 0:
            return 0.0
        return math.log(self.n_docs / df + 1)

    def score(self, query_tokens, doc_id):
        dl = self.index.doc_lengths.get(doc_id, 1)
        total = 0.0
        for term in set(query_tokens):
            tf_raw = self.index.get_postings(term).get(doc_id, 0)
            if tf_raw == 0:
                continue
            tf = tf_raw / dl  # normalized TF
            total += tf * self._idf(term)
        return total

    def rank(self, query_tokens, top_k=None):
        candidate_docs = set()
        for term in query_tokens:
            candidate_docs.update(self.index.get_postings(term).keys())
        scores = [(doc_id, self.score(query_tokens, doc_id)) for doc_id in candidate_docs]
        scores.sort(key=lambda x: x[1], reverse=True)
        if top_k is not None:
            scores = scores[:top_k]
        return scores


class BM25Scorer:
    def __init__(self, index, n_docs, k1=1.5, b=0.75):
        self.index = index
        self.n_docs = n_docs
        self.k1 = k1
        self.b = b
        total_len = sum(index.doc_lengths.values())
        self.avgdl = total_len / n_docs if n_docs > 0 else 1.0

    def _idf(self, term):
        df = self.index.df(term)
        if df == 0:
            return 0.0
        return math.log((self.n_docs - df + 0.5) / (df + 0.5) + 1)

    def score(self, query_tokens, doc_id):
        dl = self.index.doc_lengths.get(doc_id, 0)
        total = 0.0
        for term in set(query_tokens):
            tf = self.index.get_postings(term).get(doc_id, 0)
            if tf == 0:
                continue
            numerator = tf * (self.k1 + 1)
            denominator = tf + self.k1 * (1 - self.b + self.b * dl / self.avgdl)
            total += self._idf(term) * numerator / denominator
        return total

    def rank(self, query_tokens, top_k=None):
        candidate_docs = set()
        for term in query_tokens:
            candidate_docs.update(self.index.get_postings(term).keys())
        scores = [(doc_id, self.score(query_tokens, doc_id)) for doc_id in candidate_docs]
        scores.sort(key=lambda x: x[1], reverse=True)
        if top_k is not None:
            scores = scores[:top_k]
        return scores


class MMRReranker:
    def __init__(self, doc_vectors):
        # doc_vectors: dict {doc_id: np.array}
        self.doc_vectors = doc_vectors

    def _cosine(self, a, b):
        denom = (np.linalg.norm(a) + 1e-10) * (np.linalg.norm(b) + 1e-10)
        return float(np.dot(a, b) / denom)

    def rerank(self, candidates_with_scores, top_k, lambda_mmr=0.5):
        if not candidates_with_scores:
            return []
        top_k = min(top_k, len(candidates_with_scores))
        score_map = {doc_id: score for doc_id, score in candidates_with_scores}
        remaining = [doc_id for doc_id, _ in candidates_with_scores]
        max_score = max(score_map.values()) if score_map else 1.0
        rel_map = {k: v / (max_score + 1e-10) for k, v in score_map.items()}
        selected = []
        while len(selected) < top_k and remaining:
            if not selected:
                best = max(remaining, key=lambda i: rel_map.get(i, 0))
            else:
                def mmr_score(doc_id):
                    rel = rel_map.get(doc_id, 0)
                    v = self.doc_vectors.get(doc_id, np.zeros(1))
                    max_sim = max(
                        self._cosine(v, self.doc_vectors.get(s, np.zeros(1)))
                        for s in selected
                    )
                    return lambda_mmr * rel - (1 - lambda_mmr) * max_sim
                best = max(remaining, key=mmr_score)
            selected.append((best, score_map[best]))
            remaining.remove(best)
        return selected


class SearchEngine:
    def __init__(self):
        self.preprocessor = TextPreprocessor()
        self.inv_index = InvertedIndex()
        self.documents = []
        self.doc_tokens = []
        self.tfidf = None
        self.bm25 = None
        self.mmr = None
        self.vocab = []
        self.vocab_idx = {}
        self.doc_vectors = {}

    def _build_bow_vector(self, tokens):
        vec = np.zeros(len(self.vocab))
        for t in tokens:
            if t in self.vocab_idx:
                vec[self.vocab_idx[t]] += 1
        norm = np.linalg.norm(vec)
        return vec / (norm + 1e-10)

    def index(self, documents):
        self.documents = documents
        self.doc_tokens = []
        for doc_id, doc in enumerate(documents):
            tokens = self.preprocessor.process(doc)
            self.doc_tokens.append(tokens)
            self.inv_index.add_document(doc_id, tokens)
        # Build vocabulary
        all_terms = set()
        for tokens in self.doc_tokens:
            all_terms.update(tokens)
        self.vocab = sorted(all_terms)
        self.vocab_idx = {t: i for i, t in enumerate(self.vocab)}
        # Build bag-of-words vectors for MMR
        self.doc_vectors = {
            doc_id: self._build_bow_vector(tokens)
            for doc_id, tokens in enumerate(self.doc_tokens)
        }
        n = self.inv_index.n_docs
        self.tfidf = TFIDFScorer(self.inv_index, n)
        self.bm25 = BM25Scorer(self.inv_index, n)
        self.mmr = MMRReranker(self.doc_vectors)

    def search(self, query, top_k=5, method='bm25', diversity=0.5):
        query_tokens = self.preprocessor.process(query)
        if not query_tokens:
            return []
        fetch_k = min(len(self.documents), max(top_k * 3, 10))
        if method == 'tfidf':
            results = self.tfidf.rank(query_tokens, top_k=fetch_k)
        else:
            results = self.bm25.rank(query_tokens, top_k=fetch_k)
        if diversity > 0 and len(results) > 1:
            results = self.mmr.rerank(results, top_k=top_k, lambda_mmr=1.0 - diversity)
        else:
            results = results[:top_k]
        return results

